              "offset": 1858,
              "length": 127
            }
          ]
        },
        {
          "content": "mahsup hakkı bulunduğundan, söz konusu tutarlar üzerine Bankamızın rehin, hapis ve takas mahsup haklarından sonra hüküm",
          "polygon": [
            {
              "x": 0.4892,
              "y": 9.4137
            },
            {
              "x": 7.7711,
              "y": 9.4141
            },
